435→async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
436→  const cached = decodedImageCache.get(url);
437→  if (cached) return cached;
438→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
439→    const img = new Image();
440→    img.onload = () => resolve(img);
441→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
442→    img.src = url;
443→  });
444→  decodedImageCache.set(url, promise);
445→  return promise;
446→}
