448→async function cropFrameRowToDataUrl(src: string, atlasRows = 1, atlasRow = 0): Promise<CroppedFrameRowResult> {
449→  const key = `${src}|${atlasRows}|${atlasRow}`;
450→  const cached = croppedFrameRowCache.get(key);
451→  if (cached) return cached;
452→
453→  const promise = (async () => {
454→    const img = await loadDataUrlImage(src);
455→    const rows = Math.max(1, Math.floor(atlasRows));
456→    const rowHeight = Math.max(1, Math.floor(img.height / rows));
457→    const rowIndex = Math.max(0, Math.min(rows - 1, Math.floor(atlasRow)));
458→    const srcY = rowIndex * rowHeight;
459→
460→    const rowCanvas = document.createElement('canvas');
461→    rowCanvas.width = img.width;
462→    rowCanvas.height = rowHeight;
463→    const rowCtx = rowCanvas.getContext('2d');
464→    if (!rowCtx) {
465→      return { url: src, width: img.width, height: rowHeight };
466→    }
467→
468→    rowCtx.clearRect(0, 0, rowCanvas.width, rowCanvas.height);
469→    rowCtx.drawImage(img, 0, srcY, img.width, rowHeight, 0, 0, img.width, rowHeight);
470→    // Keep the full row including transparent gutters.
471→    // Template offsets are authored against the uncropped backdrop texture space.
472→    return {
473→      url: rowCanvas.toDataURL('image/png'),
474→      width: rowCanvas.width,
475→      height: rowCanvas.height,
476→    };
477→  })();
478→
479→  croppedFrameRowCache.set(key, promise);
480→  return promise;
481→}
