 1→import type { TextureEntry } from '../lib/types';
 2→
 3→export class TextureManager {
 4→  private cache = new Map<string, TextureEntry>();
 5→  whiteTex!: WebGLTexture;
 6→  private gl!: WebGL2RenderingContext;
 7→
 8→  init(gl: WebGL2RenderingContext) {
 9→    this.gl = gl;
10→    this.whiteTex = gl.createTexture()!;
11→    gl.bindTexture(gl.TEXTURE_2D, this.whiteTex);
12→    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
13→      new Uint8Array([255, 255, 255, 255]));
14→  }
15→
16→  load(path: string): TextureEntry {
17→    if (this.cache.has(path)) return this.cache.get(path)!;
18→    const gl = this.gl;
19→    const tex = gl.createTexture()!;
20→    gl.bindTexture(gl.TEXTURE_2D, tex);
21→    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
22→      new Uint8Array([255, 255, 255, 255]));
23→    const entry: TextureEntry = { tex, width: 1, height: 1, loaded: false };
24→    this.cache.set(path, entry);
25→    const img = new Image();
26→    img.onload = () => {
27→      gl.bindTexture(gl.TEXTURE_2D, tex);
28→      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, img);
29→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
30→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
31→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
32→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
33→      entry.width = img.width;
34→      entry.height = img.height;
35→      entry.loaded = true;
36→    };
37→    img.src = path;
38→    return entry;
39→  }
40→
41→  loadRepeat(path: string): TextureEntry {
42→    const key = path + '?repeat';
43→    if (this.cache.has(key)) return this.cache.get(key)!;
44→    const gl = this.gl;
45→    const tex = gl.createTexture()!;
46→    gl.bindTexture(gl.TEXTURE_2D, tex);
47→    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
48→      new Uint8Array([255, 255, 255, 255]));
49→    const entry: TextureEntry = { tex, width: 1, height: 1, loaded: false };
50→    this.cache.set(key, entry);
51→    const img = new Image();
52→    img.onload = () => {
53→      gl.bindTexture(gl.TEXTURE_2D, tex);
54→      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, img);
55→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
56→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
57→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT);
58→      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.REPEAT);
59→      entry.width = img.width;
60→      entry.height = img.height;
61→      entry.loaded = true;
62→    };
63→    img.src = path;
64→    return entry;
65→  }
66→
67→  get(path: string): WebGLTexture {
68→    const e = this.cache.get(path);
69→    return e ? e.tex : this.whiteTex;
70→  }
71→
72→  preload(paths: string[]) {
73→    paths.forEach(p => this.load(p));
74→  }
75→}
