 8→function stepCounter(current: number, target: number): number {
 9→  if (current === target) return current;
10→  const diff = target - current;
11→  const next = current + Math.sign(diff) * Math.max(1, Math.floor(Math.abs(diff) * 0.2));
12→  return Math.abs(target - next) < 2 ? target : next;
13→}
