 13→function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
 14→  let minX = Number.POSITIVE_INFINITY, maxX = Number.NEGATIVE_INFINITY;
 15→  let minY = Number.POSITIVE_INFINITY, maxY = Number.NEGATIVE_INFINITY;
 16→  let hasVisible = false;
 17→  for (const geoset of model.Geosets || []) {
 18→    if (!geoset.Faces || geoset.Faces.length === 0) continue;
 19→    const verts = geoset.Vertices;
 20→    for (let i = 0; i < verts.length; i += 3) {
 21→      const x = verts[i]; const y = verts[i + 1];
 22→      if (x < minX) minX = x; if (x > maxX) maxX = x;
 23→      if (y < minY) minY = y; if (y > maxY) maxY = y;
 24→      hasVisible = true;
 25→    }
 26→  }
 27→  return hasVisible ? { minX, maxX, minY, maxY } : null;
 28→}
