 30→function disableBackdropQuads(model: ModelType): void {
 31→  const hiddenNodes = new Set(['plane01', 'sunrise/set']);
 32→  for (const geoset of model.Geosets || []) {
 33→    const nodeIndex = geoset.Groups?.[0]?.[0];
 34→    if (nodeIndex == null) continue;
 35→    const nodeName = model.Nodes?.[nodeIndex]?.Name?.toLowerCase();
 36→    if (!nodeName || !hiddenNodes.has(nodeName)) continue;
 37→    geoset.Faces = new Uint16Array(0);
 38→  }
 39→}
