 50→  if (norm.includes('star3')) return `${base}star3.blp`;
 51→  if (norm.includes('genericglow2_32')) return `${base}GenericGlow2_32.blp`;
 52→  if (norm.includes('timeindicatorframe')) return `${base}${tile}UITile-TimeIndicatorFrame.blp`;
