 83→async function loadWidgetMaskDataUrl(race: Race): Promise<string> {
 84→  const cached = widgetMaskCache.get(race);
 85→  if (cached) return cached;
 86→  const frame = (await loadBLPMips(getFrameTexturePath(race)))[0];
 87→  if (!frame || frame.width <= 0 || frame.height <= 0) throw new Error(`Invalid frame texture for ${race}`);
 88→  const width = frame.width; const height = frame.height;
 89→  const seedX = Math.round(width * 0.49); const seedY = Math.round(height * 0.34);
 90→  const seed = findTransparentSeed(frame.data, width, height, seedX, seedY);
 91→  if (seed < 0) throw new Error(`Unable to locate clock aperture for ${race}`);
 92→  const aperture = new Uint8Array(width * height);
 93→  const queue = new Int32Array(width * height);
 94→  let head = 0; let tail = 0;
 95→  queue[tail++] = seed; aperture[seed] = 1;
 96→  while (head < tail) {
 97→    const cur = queue[head++]; const x = cur % width; const y = (cur / width) | 0;
 98→    for (const [nx, ny] of [[x-1,y],[x+1,y],[x,y-1],[x,y+1]]) {
 99→      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
100→      const next = ny * width + nx;
101→      if (aperture[next]) continue;
102→      if (frame.data[next * 4 + 3] !== 0) continue;
103→      aperture[next] = 1; queue[tail++] = next;
104→    }
105→  }
106→  const pixels = new Uint8ClampedArray(width * height * 4);
107→  for (let i = 0; i < width * height; i++) {
108→    const keep = frame.data[i * 4 + 3] > 0 || aperture[i] === 1;
109→    if (!keep) continue;
110→    const p = i * 4; pixels[p] = 255; pixels[p+1] = 255; pixels[p+2] = 255; pixels[p+3] = 255;
111→  }
112→  const canvas = document.createElement('canvas'); canvas.width = width; canvas.height = height;
113→  const ctx = canvas.getContext('2d');
114→  if (!ctx) throw new Error('Failed to create widget mask canvas');
115→  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
116→  const dataUrl = canvas.toDataURL('image/png');
117→  widgetMaskCache.set(race, dataUrl);
118→  return dataUrl;
119→}
