121→async function loadModelForRace(race: Race): Promise<ModelType> {
122→  const cached = modelCache.get(race);
123→  if (cached) return cached;
124→  const res = await fetch(getModelPath(race));
125→  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
126→  const ab = await res.arrayBuffer();
127→  const model = parseMDX(ab);
128→  disableBackdropQuads(model);
129→  modelCache.set(race, model);
130→  return model;
