133→async function loadBLPMips(path: string): Promise<ImageData[]> {
134→  const cached = blpCache.get(path);
135→  if (cached) return cached;
136→  const res = await fetch(path);
137→  if (!res.ok) throw new Error(`Failed to fetch texture ${path}`);
138→  const ab = await res.arrayBuffer();
139→  const blp = decodeBLP(ab);
140→  const mips: ImageData[] = [];
141→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
142→  for (let i = 0; i < maxLevels; i++) {
143→    const w = blp.width >> i; const h = blp.height >> i;
144→    if (w <= 0 || h <= 0) break;
145→    try {
146→      const img = getBLPImageData(blp, i);
147→      if (!img || !img.width || !img.height) break;
148→      mips.push(new ImageData(new Uint8ClampedArray(img.data), img.width, img.height));
149→      if (img.width === 1 && img.height === 1) break;
150→    } catch { break; }
151→  }
152→  if (mips.length === 0) throw new Error(`No mip levels decoded for ${path}`);
153→  blpCache.set(path, mips);
154→  return mips;
155→}
