872→function mixRgb(a: [number, number, number], b: [number, number, number], t: number): [number, number, number] {
873→  const clamped = Math.max(0, Math.min(1, t));
874→  return [
875→    Math.round(a[0] + (b[0] - a[0]) * clamped),
876→    Math.round(a[1] + (b[1] - a[1]) * clamped),
877→    Math.round(a[2] + (b[2] - a[2]) * clamped),
878→  ];
879→}
