885→function healthBarTint(pct: number): string {
886→  const p = Math.max(0, Math.min(100, pct));
887→  const low: [number, number, number] = [220, 42, 22];
888→  const mid: [number, number, number] = [238, 201, 46];
889→  const high: [number, number, number] = [67, 213, 61];
890→
891→  if (p <= 35) return rgbHex(mixRgb(low, mid, p / 35));
892→  return rgbHex(mixRgb(mid, high, (p - 35) / 65));
893→}
