914→function loadingStutterPct(ms: number): number {
915→  const stutterFrames = [
916→    [0, 82.0],
917→    [130, 82.8],
918→    [230, 82.35],
919→    [340, 83.95],
920→    [430, 83.3],
921→    [560, 85.2],
922→    [650, 84.45],
923→    [780, 87.25],
924→    [870, 86.55],
925→    [940, 88.9],
926→    [1000, 90.0],
927→  ] as const;
928→  return interpolateKeyframes(ms, stutterFrames);
929→}
