949→function loadingGlowAlphaPct(pct: number): number {
950→  const clampedPct = Math.max(0, Math.min(100, pct));
951→  // LoadBar.mdx (Birth sequence) glow alpha keys:
952→  // frame 3333:0, 13333:0, 26667:1, 26800:0.
953→  const glowAlphaFrames = [
954→    [0, 0],
955→    [42.6135, 0],
956→    [99.4332, 1],
957→    [100, 0],
958→  ] as const;
959→  return interpolateKeyframes(clampedPct, glowAlphaFrames);
960→}
